16	// runPromptsList implements the prompts list command
17	func (f *CommandFactory) runPromptsList(cmd *cobra.Command, args []string) error {
18		workingDir := f.WorkingDir
19		if workingDir == "" {
20			workingDir = "."
21		}
22	
23		// Get library path using working directory
24		cfg, err := config.LoadWithWorkingDir(workingDir)
25		if err != nil {
26			return fmt.Errorf("failed to load config: %w", err)
27		}
28	
29		var libPath string
30		if cfg.Library != nil {
31			libPath = cfg.Library.Path
32		}
33	
34		promptsDir := filepath.Join(workingDir, libPath, "prompts")
35	
36		// Check if prompts directory exists
37		if _, err := os.Stat(promptsDir); os.IsNotExist(err) {
38			_, _ = fmt.Fprintln(cmd.OutOrStdout(), "No prompts directory found")
39			return nil
40		}
41	
42		// Get search filter
43		searchFilter, _ := cmd.Flags().GetString("search")
44		verbose, _ := cmd.Flags().GetBool("verbose")
45	
46		_, _ = fmt.Fprintln(cmd.OutOrStdout(), "Available prompts:")
47		_, _ = fmt.Fprintln(cmd.OutOrStdout())
48	
49		// Walk through prompts directory
50		err = filepath.Walk(promptsDir, func(path string, info os.FileInfo, err error) error {
51			if err != nil {
52				return err
53			}
54	
55			// Skip the root directory
56			if path == promptsDir {
57				return nil
58			}
59	
60			// Get relative path
61			relPath, err := filepath.Rel(promptsDir, path)
62			if err != nil {
63				return err
64			}
65	
66			// Skip hidden files
67			if strings.HasPrefix(filepath.Base(path), ".") {
68				if info.IsDir() {
69					return filepath.SkipDir
70				}
71				return nil
72			}
73	
74			// Apply search filter if provided
75			if searchFilter != "" && !strings.Contains(strings.ToLower(path), strings.ToLower(searchFilter)) {
76				return nil
77			}
78	
79			// Print directories and markdown files
80			if info.IsDir() {
81				_, _ = fmt.Fprintf(cmd.OutOrStdout(), "📁 %s/\n", relPath)
82			} else if strings.HasSuffix(path, ".md") {
83				// Show full filename with extension in verbose mode
84				if verbose {
85					_, _ = fmt.Fprintf(cmd.OutOrStdout(), "  📝 %s\n", relPath)
86				} else {
87					// Remove .md extension for display
88					name := strings.TrimSuffix(relPath, ".md")
89					_, _ = fmt.Fprintf(cmd.OutOrStdout(), "  📝 %s\n", name)
90				}
91			}
92	
93			return nil
94		})
95	
96		return err
97	}
