100	func runPromptsShow(cmd *cobra.Command, args []string) error {
101		promptName := args[0]
102	
103		// Get working directory from command factory context
104		workingDir := "."
105		if factory, ok := cmd.Context().Value("factory").(*CommandFactory); ok {
106			workingDir = factory.WorkingDir
107		}
108	
109		// Get library path using working directory
110		cfg, err := config.LoadWithWorkingDir(workingDir)
111		if err != nil {
112			return fmt.Errorf("failed to load config: %w", err)
113		}
114	
115		var libPath string
116		if cfg.Library != nil {
117			libPath = cfg.Library.Path
118		}
119	
120		// Try different paths for the prompt
121		possiblePaths := []string{
122			filepath.Join(libPath, "prompts", promptName+".md"),
123			filepath.Join(libPath, "prompts", promptName),
124			filepath.Join(libPath, "prompts", promptName, "README.md"),
125		}
126	
127		var promptPath string
128		for _, path := range possiblePaths {
129			if _, err := os.Stat(path); err == nil {
130				promptPath = path
131				break
132			}
133		}
134	
135		if promptPath == "" {
136			return fmt.Errorf("prompt not found: %s", promptName)
137		}
138	
139		// Read and display the prompt
140		content, err := os.ReadFile(promptPath)
141		if err != nil {
142			return fmt.Errorf("failed to read prompt: %w", err)
143		}
144	
145		_, _ = fmt.Fprint(cmd.OutOrStdout(), string(content))
146		return nil
147	}
