11		"github.com/DocumentDrivenDX/ddx/internal/bead"
12		internalgit "github.com/DocumentDrivenDX/ddx/internal/git"
13	)
14	
15	// OperatorPromptBacklinkEventKind is the BeadEvent.Kind appended to every
16	// bead created or modified by the execution of an operator-prompt bead. The
17	// event body carries the originating operator-prompt's ID so downstream
18	// audit tooling (UI, evidence reports) can trace any later mutation back
19	// to the prompt that introduced it. A summary event with the same kind is
20	// also appended to the originator listing every affected bead and artifact
21	// path so a single read on the operator-prompt bead surfaces the full
22	// blast radius. (FEAT operator-prompts, Story 15 §Additional security
23	// controls bullet 6.)
24	const OperatorPromptBacklinkEventKind = "origin_operator_prompt_id"
25	
26	// operatorPromptAffected lists the beads created/modified and the artifact
27	// paths touched by an operator-prompt bead's harness during one successful
28	// attempt. It is the input to RecordOperatorPromptBacklinks.
29	type operatorPromptAffected struct {
30		BeadIDs   []string
31		Artifacts []string
32	}
33	
34	// computeOperatorPromptAffected diffs base..result in projectRoot and
35	// classifies the changed paths. Mutations to the bead JSONL stores
36	// (.ddx/beads.jsonl and .ddx/beads-archive.jsonl) yield bead IDs (parsed
37	// out of the added-line JSON); every other changed path is treated as an
38	// artifact. The originator's own ID is filtered out so the originator
39	// does not back-link to itself. Returns nil/empty fields when base==result
40	// or no diff is available.
41	func computeOperatorPromptAffected(projectRoot, baseRev, resultRev, originatorID string) (operatorPromptAffected, error) {
42		if projectRoot == "" || baseRev == "" || resultRev == "" || baseRev == resultRev {
43			return operatorPromptAffected{}, nil
44		}
45		gitOps := RealLandingGitOps{}
46		paths, err := gitOps.DiffNameOnly(projectRoot, baseRev, resultRev)
47		if err != nil {
48			return operatorPromptAffected{}, fmt.Errorf("operator-prompt backlinks: diff %s..%s: %w", baseRev, resultRev, err)
49		}
50	
51		beadIDSet := map[string]struct{}{}
52		var artifacts []string
53		for _, p := range paths {
54			switch p {
55			case ".ddx/beads.jsonl", ".ddx/beads-archive.jsonl":
56				ids, perr := extractBeadIDsFromDiff(projectRoot, baseRev, resultRev, p)
57				if perr != nil {
58					return operatorPromptAffected{}, perr
59				}
60				for _, id := range ids {
61					beadIDSet[id] = struct{}{}
62				}
63			default:
64				artifacts = append(artifacts, p)
65			}
66		}
67		delete(beadIDSet, originatorID)
68	
69		beadIDs := make([]string, 0, len(beadIDSet))
70		for id := range beadIDSet {
71			beadIDs = append(beadIDs, id)
72		}
73		sort.Strings(beadIDs)
74		sort.Strings(artifacts)
75		return operatorPromptAffected{BeadIDs: beadIDs, Artifacts: artifacts}, nil
76	}
77	
78	// extractBeadIDsFromDiff parses `git diff base tip -- path` and returns the
79	// IDs from every added line that decodes as a bead JSON object. Only added
80	// lines are considered (a deletion alone is not a "create or modify" of a
81	// bead — closed beads still see a status-change diff and so still appear
82	// as added lines). Best-effort: malformed JSON lines are silently skipped.
83	func extractBeadIDsFromDiff(projectRoot, baseRev, resultRev, path string) ([]string, error) {
84		out, err := internalgit.Command(context.Background(), projectRoot, "diff", "--no-color", "--unified=0", baseRev, resultRev, "--", path).CombinedOutput()
85		if err != nil {
86			return nil, fmt.Errorf("operator-prompt backlinks: diff %s: %s: %w", path, strings.TrimSpace(string(out)), err)
87		}
88		var ids []string
89		seen := map[string]struct{}{}
90		for _, line := range strings.Split(string(out), "\n") {
91			if !strings.HasPrefix(line, "+") || strings.HasPrefix(line, "+++") {
92				continue
93			}
94			body := strings.TrimSpace(line[1:])
95			if body == "" || body[0] != '{' {
96				continue
97			}
98			var rec struct {
99				ID string `json:"id"`
100			}
101			if err := json.Unmarshal([]byte(body), &rec); err != nil || rec.ID == "" {
102				continue
103			}
104			if _, ok := seen[rec.ID]; ok {
105				continue
106			}
107			seen[rec.ID] = struct{}{}
108			ids = append(ids, rec.ID)
109		}
110		return ids, nil
111	}
