113	// recordOperatorPromptBacklinks appends `origin_operator_prompt_id` events
114	// to every bead in affected.BeadIDs (back-link from each affected bead to
115	// the originator) and one summary event on the originator listing every
116	// affected bead + artifact path. Idempotent across a single attempt:
117	// re-running with the same affected set produces an additional event per
118	// affected bead — callers must guard against double-invocation. Errors on
119	// individual AppendEvent calls are reported as a joined error string but
120	// do NOT short-circuit subsequent appends, so a single store hiccup does
121	// not lose every other backlink.
122	func recordOperatorPromptBacklinks(store ExecuteBeadLoopStore, originatorID string, affected operatorPromptAffected, actor string, now time.Time) error {
123		if originatorID == "" {
124			return fmt.Errorf("operator-prompt backlinks: originator ID is required")
125		}
126		if len(affected.BeadIDs) == 0 && len(affected.Artifacts) == 0 {
127			return nil
128		}
129		var errs []string
130		body := fmt.Sprintf("origin_operator_prompt_id=%s", originatorID)
131		for _, id := range affected.BeadIDs {
132			if err := store.AppendEvent(id, bead.BeadEvent{
133				Kind:      OperatorPromptBacklinkEventKind,
134				Summary:   "operator-prompt backlink",
135				Body:      body,
136				Actor:     actor,
137				Source:    "ddx agent execute-loop",
138				CreatedAt: now,
139			}); err != nil {
140				errs = append(errs, fmt.Sprintf("%s: %v", id, err))
141			}
142		}
143		// Summary event on the originator: lists every affected bead/artifact.
144		summaryBody := fmt.Sprintf(
145			"affected_beads=%s affected_artifacts=%s",
146			strings.Join(affected.BeadIDs, ","),
147			strings.Join(affected.Artifacts, ","),
148		)
149		if err := store.AppendEvent(originatorID, bead.BeadEvent{
150			Kind:      OperatorPromptBacklinkEventKind,
151			Summary:   "operator-prompt blast radius",
152			Body:      summaryBody,
153			Actor:     actor,
154			Source:    "ddx agent execute-loop",
155			CreatedAt: now,
156		}); err != nil {
157			errs = append(errs, fmt.Sprintf("originator %s: %v", originatorID, err))
158		}
159		if len(errs) > 0 {
160			return fmt.Errorf("operator-prompt backlinks: %s", strings.Join(errs, "; "))
161		}
162		return nil
163	}
