8	// RepairPromptInput carries the evidence needed to ask an implementer to make
9	// one append-only repair commit in the still-live attempt worktree.
10	type RepairPromptInput struct {
11		BeadID               string
12		BaseRev              string
13		FailedCandidateRev   string
14		CycleIndex           int
15		ReviewRationale      string
16		PerAC                []ReviewAC
17		Findings             []Finding
18		VerificationCommands []string
19	}
20	
21	// BuildRepairPrompt assembles the same-worktree repair prompt. The prompt is
22	// intentionally policy-heavy: repair passes may add one commit, but must never
23	// rewrite the existing implementation history.
24	func BuildRepairPrompt(input RepairPromptInput) string {
25		var b strings.Builder
26		fmt.Fprintf(&b, "Repair bead %s in the current attempt worktree.\n\n", input.BeadID)
27		fmt.Fprintf(&b, "base_rev: %s\n", input.BaseRev)
28		fmt.Fprintf(&b, "failed_candidate_rev: %s\n", input.FailedCandidateRev)
29		fmt.Fprintf(&b, "repair_cycle_index: %d\n\n", input.CycleIndex)
30	
31		b.WriteString("Review findings:\n")
32		if strings.TrimSpace(input.ReviewRationale) != "" {
33			fmt.Fprintf(&b, "- %s\n", strings.TrimSpace(input.ReviewRationale))
34		}
35		for _, finding := range input.Findings {
36			line := strings.TrimSpace(finding.Summary)
37			if line == "" {
38				continue
39			}
40			if loc := strings.TrimSpace(finding.Location); loc != "" {
41				line = loc + ": " + line
42			}
43			if sev := strings.TrimSpace(finding.Severity); sev != "" {
44				line = sev + ": " + line
45			}
46			fmt.Fprintf(&b, "- %s\n", line)
47		}
48	
49		b.WriteString("\nPer-AC failures:\n")
50		for _, ac := range input.PerAC {
51			if strings.TrimSpace(ac.Evidence) == "" && strings.TrimSpace(ac.Grade) == "" {
52				continue
53			}
54			fmt.Fprintf(&b, "- AC#%d %s %s %s\n", ac.Number, strings.TrimSpace(ac.Item), strings.TrimSpace(ac.Grade), strings.TrimSpace(ac.Evidence))
55		}
56	
57		b.WriteString("\nVerification commands:\n")
58		for _, cmd := range input.VerificationCommands {
59			if strings.TrimSpace(cmd) == "" {
60				continue
61			}
62			fmt.Fprintf(&b, "- %s\n", strings.TrimSpace(cmd))
63		}
64	
65		b.WriteString("\nRules:\n")
66		b.WriteString("- Work in the existing attempt worktree only.\n")
67		b.WriteString("- Make exactly one append-only repair commit on top of the failed candidate.\n")
68		b.WriteString("- Do not reset, amend, squash, rebase, cherry-pick over, or otherwise rewrite history.\n")
69		b.WriteString("- Limit changes to the reviewer findings and the bead acceptance criteria.\n")
70		return b.String()
71	}
