17	// representativePromptBead returns the deterministic bead used by the
18	// prompt-size fixture and the prompt_sha test. Holding it constant means
19	// rendered prompt sha and word/byte counts only change when the static
20	// instructions change — which is exactly what we want to surface.
21	func representativePromptBead() *bead.Bead {
22		return &bead.Bead{
23			ID:    "ddx-promptsize-fixture",
24			Title: "Representative bead for prompt-size measurement",
25			Description: "Static fixture used by Story 12 prompt-size report and " +
26				"prompt_sha analytics. Description body is deliberately ordinary " +
27				"prose so word/byte counts reflect the static instructions, not " +
28				"the bead body.",
29			Acceptance: "AC1: prompt renders deterministically.\n" +
30				"AC2: word and byte counts are reported per (variant, contextBudget).",
31			Labels: []string{"phase:2", "story:12", "tier:cheap"},
32			Extra:  map[string]any{"spec-id": "FEAT-022"},
33		}
34	}
35	
36	// renderPromptForSize renders a prompt for the given harness selector and
37	// contextBudget using a fixed in-memory artifact bundle. It does not touch
38	// the filesystem so the fixture is hermetic.
39	func renderPromptForSize(t *testing.T, harness, contextBudget string) []byte {
40		t.Helper()
41		const attemptID = "20260101T000000-promptsize"
42		arts := &executeBeadArtifacts{
43			DirRel:      ".ddx/executions/" + attemptID,
44			PromptRel:   ".ddx/executions/" + attemptID + "/prompt.md",
45			ManifestRel: ".ddx/executions/" + attemptID + "/manifest.json",
46			ResultRel:   ".ddx/executions/" + attemptID + "/result.json",
47			ChecksRel:   ".ddx/executions/" + attemptID + "/checks.json",
48			UsageRel:    ".ddx/executions/" + attemptID + "/usage.json",
49		}
50		b := representativePromptBead()
51		// Empty refs to keep the fixture hermetic — buildPrompt will emit the
52		// missing-governing fallback note for the non-minimal budget, which
53		// matches the AC for that case.
54		content, _, err := buildPrompt(t.TempDir(), b, nil, arts, "deadbeefdeadbeef", "", harness, contextBudget)
55		if err != nil {
56			t.Fatalf("buildPrompt(%s, %q): %v", harness, contextBudget, err)
57		}
58		return content
59	}
60	
61	// TestPromptSizeReport renders the execute-bead prompt for both variants
62	// (Claude harness, Agent harness) at each contextBudget label ("" full,
63	// "minimal") and writes a deterministic word/byte report. CI uploads the
64	// report path named by DDX_PROMPT_SIZE_REPORT as an artifact so accidental
65	// prompt bloat shows up as a diff in the artifact across runs.
66	func TestPromptSizeReport(t *testing.T) {
67		type row struct {
68			Variant       string `json:"variant"`
69			Harness       string `json:"harness"`
70			ContextBudget string `json:"context_budget"`
71			Words         int    `json:"words"`
72			Bytes         int    `json:"bytes"`
73			PromptSHA     string `json:"prompt_sha"`
74		}
75		const (
76			fullByteBudget    = 6400
77			minimalByteBudget = 6200
78		)
79	
80		// Selector at execute_bead.go routes (agent|fiz|embedded) to the Agent
81		// variant; everything else (claude/codex/opencode/unknown) to the Claude
82		// variant. One representative harness per variant is enough.
83		cases := []struct{ variant, harness string }{
84			{"claude", "claude"},
85			{"agent", "agent"},
86		}
87		budgets := []string{"", "minimal"}
88	
89		rows := make([]row, 0, len(cases)*len(budgets))
90		for _, c := range cases {
91			for _, budget := range budgets {
92				content := renderPromptForSize(t, c.harness, budget)
93				sum := sha256.Sum256(content)
94				rows = append(rows, row{
95					Variant:       c.variant,
96					Harness:       c.harness,
97					ContextBudget: budget,
98					Words:         len(strings.Fields(string(content))),
99					Bytes:         len(content),
100					PromptSHA:     hex.EncodeToString(sum[:]),
101				})
102			}
103		}
104	
105		sort.Slice(rows, func(i, j int) bool {
106			if rows[i].Variant != rows[j].Variant {
107				return rows[i].Variant < rows[j].Variant
108			}
109			return rows[i].ContextBudget < rows[j].ContextBudget
110		})
111	
112		var report strings.Builder
113		report.WriteString("# execute-bead prompt size report\n")
114		report.WriteString("# variant\tharness\tcontext_budget\twords\tbytes\tprompt_sha\n")
115		for _, r := range rows {
116			budget := r.ContextBudget
117			if budget == "" {
118				budget = "full"
119			}
120			fmt.Fprintf(&report, "%s\t%s\t%s\t%d\t%d\t%s\n",
121				r.Variant, r.Harness, budget, r.Words, r.Bytes, r.PromptSHA)
122		}
123	
124		// Always log the report to test output — that alone makes CI surface
125		// it via the existing test-log capture even if the artifact step is
126		// not configured.
127		t.Logf("\n%s", report.String())
128	
129		// Sanity: every row produced non-empty output.
130		for _, r := range rows {
131			if r.Words == 0 || r.Bytes == 0 {
132				t.Errorf("empty rendered prompt for variant=%s budget=%q", r.Variant, r.ContextBudget)
133			}
134		}
135		// Hard ceiling: the prompt report is a CI fixture, so it should fail if
136		// the rendered prompt grows past the measured byte budgets.
137		for _, r := range rows {
138			limit := fullByteBudget
139			if r.ContextBudget == "minimal" {
140				limit = minimalByteBudget
141			}
142			if r.Bytes > limit {
143				t.Errorf("variant=%s budget=%q rendered %d bytes; must be <= %d",
144					r.Variant, r.ContextBudget, r.Bytes, limit)
145			}
146		}
147		// Minimal must be strictly smaller than full for both variants — the
148		// fixture's reason for existing is to catch regressions on the cheap-tier
149		// path.
150		byKey := map[string]row{}
151		for _, r := range rows {
152			byKey[r.Variant+"|"+r.ContextBudget] = r
153		}
154		for _, v := range []string{"claude", "agent"} {
155			full := byKey[v+"|"]
156			min := byKey[v+"|minimal"]
157			if min.Bytes >= full.Bytes {
158				t.Errorf("variant %s: minimal bytes %d not smaller than full bytes %d",
159					v, min.Bytes, full.Bytes)
160			}
161		}
162	
163		// Write the human-readable report alongside a JSON sibling for
164		// machine consumers. CI sets DDX_PROMPT_SIZE_REPORT to a path under the
165		// workspace and uploads it as an artifact; locally the test falls back
166		// to t.TempDir() so it never pollutes the working tree.
167		outPath := strings.TrimSpace(os.Getenv("DDX_PROMPT_SIZE_REPORT"))
168		if outPath == "" {
169			outPath = filepath.Join(t.TempDir(), "prompt-size-report.txt")
170		}
171		if err := os.MkdirAll(filepath.Dir(outPath), 0o755); err != nil {
172			t.Fatalf("mkdir report dir: %v", err)
173		}
174		if err := os.WriteFile(outPath, []byte(report.String()), 0o644); err != nil {
175			t.Fatalf("writing prompt-size report: %v", err)
176		}
177		jsonPath := strings.TrimSuffix(outPath, filepath.Ext(outPath)) + ".json"
178		jb, err := json.MarshalIndent(rows, "", "  ")
179		if err != nil {
180			t.Fatalf("marshal rows: %v", err)
181		}
182		if err := os.WriteFile(jsonPath, append(jb, '\n'), 0o644); err != nil {
183			t.Fatalf("writing prompt-size report json: %v", err)
184		}
185		t.Logf("prompt-size report written to %s (and %s)", outPath, jsonPath)
186	}
187	
188	// TestPromptSHA_DeterministicAcrossRenders asserts that the helper
189	// promptSHA used to populate manifest.prompt_sha is stable across renders
190	// of the same inputs. Without this, analytics grouping by prompt_sha would
191	// fragment across attempts that share a prompt.
192	func TestPromptSHA_DeterministicAcrossRenders(t *testing.T) {
193		a := renderPromptForSize(t, "claude", "")
194		b := renderPromptForSize(t, "claude", "")
195		if promptSHA(a) != promptSHA(b) {
196			t.Fatalf("promptSHA not deterministic: %s vs %s", promptSHA(a), promptSHA(b))
197		}
198		c := renderPromptForSize(t, "agent", "")
199		if promptSHA(a) == promptSHA(c) {
200			t.Fatalf("promptSHA collided across variants — selector is not influencing the prompt body")
201		}
202	}
